const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION MULTI-DESTINATION - MOBILITÉS INTERNES (avec BAALLAH)');
console.log('═══════════════════════════════════════════════════');
console.log(`Mobilités reçues: ${items.length}`);

// ─── EXPANSION MULTI-NIVEAUX ───
const lignesExpansees = [];

items.forEach(item => {
  const data = item.json;
  const jr = data.jours_restants;
  const delai = parseInt(data.delai_int || data.delai_total_jours || 10);

  const niveauxActifs = [];

  if (jr <= 2)                                      niveauxActifs.push('PDG');
  if (jr === 3)                                     niveauxActifs.push('SUPERIEUR');
  if (jr === 4)                                     niveauxActifs.push('SALARIE');
  if (jr >= 5 && jr <= 8)                          niveauxActifs.push('FARHAT');
  if (jr > 4 && jr <= Math.floor(delai / 2))       niveauxActifs.push('DGA');
  if (jr > 4 && jr <= Math.floor(delai / 2))       niveauxActifs.push('BAALLAH');

  niveauxActifs.forEach(niveau => {
    lignesExpansees.push({ data, niveau });
  });
});

console.log(`Lignes après expansion multi-niveaux: ${lignesExpansees.length}`);

// ─── GROUPEMENT PAR DESTINATAIRE ───
const notifications = {};

lignesExpansees.forEach(({ data, niveau }) => {

  let destinatairePrincipal;
  let codeDestinataire;

  switch (niveau) {
    case 'PDG':
      destinatairePrincipal = {
        code: data.code_pdg, nom: data.nom_pdg, prenom: data.prenom_pdg,
        email: data.email_pdg, telephone: data.telephone_pdg,
        chat_id: data.chat_id_pdg, langue: data.langue_pdg, bot: data.bot_pdg
      };
      codeDestinataire = data.code_pdg;
      break;

    case 'DGA':
      destinatairePrincipal = {
        code: data.code_dga, nom: data.nom_dga, prenom: data.prenom_dga,
        email: data.email_dga, telephone: data.telephone_dga,
        chat_id: data.chat_id_dga, langue: data.langue_dga, bot: data.bot_dga
      };
      codeDestinataire = data.code_dga;
      break;

    case 'BAALLAH':
      destinatairePrincipal = {
        code: data.code_baallah, nom: data.nom_baallah, prenom: data.prenom_baallah,
        email: data.email_baallah || null, telephone: data.telephone_baallah || null,
        chat_id: data.chat_id_baallah || null, langue: data.langue_baallah || 'FRA', bot: data.bot_baallah || null
      };
      codeDestinataire = data.code_baallah;
      break;

    case 'SUPERIEUR':
      destinatairePrincipal = {
        code: data.code_superieur, nom: data.nom_superieur, prenom: data.prenom_superieur,
        email: data.email_superieur, telephone: data.num_telephone_sup,
        chat_id: data.chat_id_superieur, langue: data.langue_superieur, bot: data.bot_superieur
      };
      codeDestinataire = data.code_superieur;
      break;

    case 'SALARIE':
      destinatairePrincipal = {
        code: data.code_salarie, nom: data.nom_salarie, prenom: data.prenom_salarie,
        email: data.email_salarie, telephone: data.num_telephone_salarie,
        chat_id: data.chat_id_salarie, langue: data.langue_salarie, bot: data.bot_salarie
      };
      codeDestinataire = data.code_salarie;
      break;

    case 'FARHAT':
      destinatairePrincipal = {
        code: data.code_farhat, nom: data.nom_farhat, prenom: data.prenom_farhat,
        email: data.email_farhat || null, telephone: data.telephone_farhat || null,
        chat_id: data.chat_id_farhat || null, langue: data.langue_farhat || 'FRA', bot: data.bot_farhat || null
      };
      codeDestinataire = data.code_farhat;
      break;

    default:
      return;
  }

  const cleDestinataire = `${niveau}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire: niveau,
      niveau_escalade: niveau,

      salarie: {
        code: data.code_salarie, nom: data.nom_salarie, prenom: data.prenom_salarie,
        email: data.email_salarie, telephone: data.num_telephone_salarie,
        chat_id: data.chat_id_salarie, langue: data.langue_salarie, bot: data.bot_salarie
      },
      superieur: {
        code: data.code_superieur, nom: data.nom_superieur, prenom: data.prenom_superieur,
        email: data.email_superieur, telephone: data.num_telephone_sup,
        chat_id: data.chat_id_superieur, langue: data.langue_superieur, bot: data.bot_superieur
      },
      pdg: {
        code: data.code_pdg, nom: data.nom_pdg, prenom: data.prenom_pdg,
        email: data.email_pdg, telephone: data.telephone_pdg,
        chat_id: data.chat_id_pdg, langue: data.langue_pdg, bot: data.bot_pdg
      },
      dga: {
        code: data.code_dga, nom: data.nom_dga, prenom: data.prenom_dga,
        email: data.email_dga, telephone: data.telephone_dga,
        chat_id: data.chat_id_dga, langue: data.langue_dga, bot: data.bot_dga
      },
      farhat: {
        code: data.code_farhat, nom: data.nom_farhat, prenom: data.prenom_farhat,
        email: data.email_farhat, telephone: data.telephone_farhat,
        chat_id: data.chat_id_farhat, langue: data.langue_farhat, bot: data.bot_farhat
      },
      baallah: {
        code: data.code_baallah, nom: data.nom_baallah, prenom: data.prenom_baallah,
        email: data.email_baallah, telephone: data.telephone_baallah,
        chat_id: data.chat_id_baallah, langue: data.langue_baallah || 'FRA', bot: data.bot_baallah
      },
      attestations: []
    };
  }

  // Éviter les doublons de mobilités dans le même groupe
  const dejaPresent = notifications[cleDestinataire].attestations
    .some(a => a.numero_attestation === data.numero_mobilite);

  if (!dejaPresent) {
    notifications[cleDestinataire].attestations.push({
      numero_attestation: data.numero_mobilite,
      date_creation_attestation: data.date_creation_mobilite,
      date_controle: data.date_controle,
      utilisateur_createur: data.utilisateur_createur,
      delai_total_jours: data.delai_total_jours,
      date_limite: data.date_limite,
      jours_depuis_creation: data.jours_depuis_creation,
      jours_restants: data.jours_restants,
      salarie_concerne: {
        code: data.code_salarie,
        nom: data.nom_salarie,
        prenom: data.prenom_salarie,
        email: data.email_salarie,
        telephone: data.num_telephone_salarie
      }
    });
  }
});

// ─── FORMATAGE FINAL ───
const resultats = Object.values(notifications).map(notif => {
  const joursMin = Math.min(...notif.attestations.map(a => a.jours_restants));
  const joursMax = Math.max(...notif.attestations.map(a => a.jours_restants));
  const delaiTotal = parseInt(notif.attestations[0]?.delai_total_jours) || 10;

  let emailCC = [];
  let chatIDsCC = [];

  if (notif.type_destinataire === 'PDG') {
    if (notif.superieur.email) emailCC.push(notif.superieur.email);
    if (notif.salarie.email)   emailCC.push(notif.salarie.email);
    if (notif.dga.email)       emailCC.push(notif.dga.email);
    [notif.superieur, notif.salarie, notif.dga].forEach(p => {
      if (p.chat_id) chatIDsCC.push({ chat_id: p.chat_id, bot: p.bot, langue: p.langue, nom: `${p.prenom} ${p.nom}` });
    });

  } else if (notif.type_destinataire === 'DGA') {
    if (notif.superieur.email) emailCC.push(notif.superieur.email);
    if (notif.salarie.email)   emailCC.push(notif.salarie.email);
    [notif.superieur, notif.salarie].forEach(p => {
      if (p.chat_id) chatIDsCC.push({ chat_id: p.chat_id, bot: p.bot, langue: p.langue, nom: `${p.prenom} ${p.nom}` });
    });

  } else if (notif.type_destinataire === 'BAALLAH') {
    // BAALLAH → pas de CC, email + Telegram si chat_id disponible

  } else if (notif.type_destinataire === 'SUPERIEUR') {
    if (notif.salarie.email)   emailCC.push(notif.salarie.email);
    if (notif.salarie.chat_id) chatIDsCC.push({
      chat_id: notif.salarie.chat_id, bot: notif.salarie.bot,
      langue: notif.salarie.langue, nom: `${notif.salarie.prenom} ${notif.salarie.nom}`
    });

  } else if (notif.type_destinataire === 'FARHAT') {
    // Pas de CC pour FARHAT
  }
  // SALARIE → pas de CC

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire: notif.type_destinataire,
    niveau_escalade: notif.niveau_escalade,
    email_cc: emailCC.length > 0 ? emailCC.join(',') : null,
    telegram_cc: chatIDsCC.length > 0 ? chatIDsCC : null,
    salarie: notif.salarie,
    superieur: notif.superieur,
    pdg: notif.pdg,
    dga: notif.dga,
    farhat: notif.farhat,
    baallah: notif.baallah,
    attestations: notif.attestations,
    statistiques: {
      total_attestations: notif.attestations.length,
      jours_min: joursMin,
      jours_max: joursMax,
      priorite: notif.niveau_escalade,
      delai_total: delaiTotal,
      seuil_mi_delai: Math.floor(delaiTotal / 2)
    },
    meta: {
      date_traitement: new Date().toISOString(),
      langue_message: notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email: !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

console.log(`\n✅ Notifications structurées: ${resultats.length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  const n = resultats.filter(r => r.type_destinataire === t).length;
  if (n > 0) console.log(`  - ${t}: ${n}`);
});
